import React, { useContext } from 'react';

import { Container } from 'react-bootstrap';

// Importaciones de Contextos (Solo para que no falle la compilación)

import { SettingsContext } from '../context/SettingsContext';



const Header = () => {

  const { settings } = useContext(SettingsContext);



  // NOTA: Se eliminó toda la lógica de usuario, carrito, búsqueda y esqueletos.

 

  // CRÍTICO: Definimos el estilo inline para forzar el redondeo superior

  const headerStyle = {

    backgroundColor: 'var(--brand-dark)',

    // Forzamos el redondeo superior con CSS, ya que Tailwind falla por conflicto.

    borderTopLeftRadius: '1.5rem',

    borderTopRightRadius: '1.5rem',

    // Aseguramos que el redondeo inferior sea CERO, si es que HeroSection ya lo tiene.

    borderBottomLeftRadius: '0',

    borderBottomRightRadius: '0',

  };

 

  return (

    // Aplicamos el estilo inline y eliminamos las clases de redondeo de Tailwind

    <header

      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md"

      style={headerStyle}

    >

      <Container className="py-4 text-white text-center font-bold">

        {/* Este texto solo es para confirmar que el Header está cargado */}

        HEADER: Prueba de Redondeo Superior

      </Container>

    </header>

  );

};



export default Header;
